window.docContents[165].resolve({"/Installation-and-Setup/#Lean-Machine-Learning--Installation-and-Setup--Installing-the-Lean-Machine-Learning-library":{"contents":"There are two ways to get the library depending on your needs:\n\n1. Clone the repository: if you want to explore the source code and experiment with modifications of the library, clone the GitHub repository2. Use as a dependency: if you want to use the library in your own Lean project, you can add it as a dependency in your lakefile.toml (instructions below)\n\n\n\n\n\n","context":"Lean Machine Learning\u0009Installation and Setup","header":"1.2. Installing the Lean Machine Learning library","id":"/Installation-and-Setup/#Lean-Machine-Learning--Installation-and-Setup--Installing-the-Lean-Machine-Learning-library"}});